<?php header("Access-Control-Allow-Origin: *");header("Access-Control-Allow-Headers: *");header("Access-Control-Allow-Methods: *");header("Content-Type: application/json");$file='db.json';$method=$_SERVER['REQUEST_METHOD'];$id=$_GET['id']??'';$db=file_exists($file)?json_decode(file_get_contents($file),true):["produk"=>[]];if(!$db||!isset($db['produk']))$db=["produk"=>[]];if($method==='GET'){echo json_encode($db['produk']);exit;}if($method==='POST'){$input=json_decode(file_get_contents('php://input'),true);if(!is_array($input))$input=[];$input['id']=strval(time());$db['produk'][]=$input;file_put_contents($file,json_encode($db,JSON_PRETTY_PRINT));echo json_encode(["status"=>"sukses","produk"=>$input]);exit;}if($method==='DELETE'){$idStr=strval($id);if($idStr==='all'||$idStr===''){ $db['produk']=[]; }else{$db['produk']=array_values(array_filter($db['produk'],fn($p)=>strval($p['id']??'')!==$idStr));}file_put_contents($file,json_encode($db,JSON_PRETTY_PRINT));echo json_encode(["status"=>"sukses menghapus","id"=>$idStr]);exit;}echo json_encode(["status"=>"method tidak didukung"]);
?>
